"use client";
import { useState, useEffect, useCallback, useRef } from "react";

const IMAGES = [
  { src: "data:image/jpeg;base64," },
  { src: "data:image/jpeg;base64," },
  { src: "data:image/jpeg;base64," },
  { src: "data:image/jpeg;base64," },
  { src: "data:image/jpeg;base64," },
  { src: "data:image/jpeg;base64," },
  { src: "data:image/jpeg;base64," },
  { src: "data:image/jpeg;base64," }
];

function isSolvable(arr, n) {
  let inv = 0;
  const flat = arr.filter((x) => x !== n * n - 1);
  for (let i = 0; i < flat.length; i++)
    for (let j = i + 1; j < flat.length; j++)
      if (flat[i] > flat[j]) inv++;
  if (n % 2 === 1) return inv % 2 === 0;
  const emptyRow = Math.floor(arr.indexOf(n * n - 1) / n);
  return (inv + emptyRow) % 2 === 1;
}

function doShuffle(n) {
  const arr = Array.from({ length: n * n }, (_, i) => i);
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  if (!isSolvable(arr, n)) {
    const a = arr[0] === n * n - 1 ? 1 : 0;
    const b = arr[1] === n * n - 1 ? 2 : 1;
    [arr[a], arr[b]] = [arr[b], arr[a]];
  }
  return arr;
}

const C = {
  bg: "#f4f9f7", card: "#ffffff", border: "#d4e8e0",
  accent: "#4ab88c", accentSoft: "#e6f5ef", accentMid: "#a3d9c2",
  text: "#2d3b35", textSoft: "#7a9389", textMuted: "#b0c5bb",
};
const font = "'DM Sans', 'Pretendard', -apple-system, sans-serif";

export default function PuzzleGame() {
  const [n, setN] = useState(4);
  const [board, setBoard] = useState(() => doShuffle(4));
  const [moves, setMoves] = useState(0);
  const [sec, setSec] = useState(0);
  const [started, setStarted] = useState(false);
  const [won, setWon] = useState(false);
  const [showHint, setShowHint] = useState(false);
  const [selIdx, setSelIdx] = useState(0);
  const [showGallery, setShowGallery] = useState(false);
  const timerRef = useRef(null);

  const imgSrc = IMAGES[selIdx]?.src || IMAGES[0]?.src;
  const SIZE = Math.min(380, typeof window !== "undefined" ? window.innerWidth - 60 : 380);
  const T = SIZE / n;

  useEffect(() => {
    if (started && !won) {
      timerRef.current = setInterval(() => setSec((s) => s + 1), 1000);
    }
    return () => clearInterval(timerRef.current);
  }, [started, won]);

  const reset = useCallback((newN) => {
    const sz = newN || n;
    setN(sz);
    setBoard(doShuffle(sz));
    setMoves(0); setSec(0); setStarted(false); setWon(false);
    clearInterval(timerRef.current);
  }, [n]);

  const emptyPos = board.indexOf(n * n - 1);

  const tryMove = useCallback((pos) => {
    if (won) return;
    const eC = emptyPos % n, eR = Math.floor(emptyPos / n);
    const c = pos % n, r = Math.floor(pos / n);
    if ((Math.abs(c - eC) === 1 && r === eR) || (Math.abs(r - eR) === 1 && c === eC)) {
      if (!started) setStarted(true);
      const nb = [...board];
      [nb[pos], nb[emptyPos]] = [nb[emptyPos], nb[pos]];
      setBoard(nb);
      setMoves((m) => m + 1);
      let w = true;
      for (let i = 0; i < nb.length; i++) { if (nb[i] !== i) { w = false; break; } }
      if (w) setWon(true);
    }
  }, [board, emptyPos, n, started, won]);

  useEffect(() => {
    const handler = (e) => {
      if (won) return;
      const eC = emptyPos % n, eR = Math.floor(emptyPos / n);
      let t = -1;
      if (e.key === "ArrowUp" && eR < n - 1) t = (eR + 1) * n + eC;
      if (e.key === "ArrowDown" && eR > 0) t = (eR - 1) * n + eC;
      if (e.key === "ArrowLeft" && eC < n - 1) t = eR * n + eC + 1;
      if (e.key === "ArrowRight" && eC > 0) t = eR * n + eC - 1;
      if (t >= 0) { e.preventDefault(); tryMove(t); }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [tryMove, emptyPos, n, won]);

  const selectImage = (idx) => { setSelIdx(idx); reset(n); setShowGallery(false); };
  const fmt = (s) => `${Math.floor(s / 60)}:${(s % 60 < 10 ? "0" : "") + (s % 60)}`;

  const btnS = (active) => ({
    padding: "8px 18px",
    border: `1.5px solid ${active ? C.accent : C.border}`,
    background: active ? C.accentSoft : C.card,
    color: active ? C.accent : C.textSoft,
    fontSize: 13, fontWeight: 600, borderRadius: 10,
    cursor: "pointer", letterSpacing: 0.3, transition: "all 0.15s", fontFamily: font,
  });

  return (
    <div style={{
      minHeight: "100vh", display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center",
      background: C.bg, fontFamily: font, position: "relative",
    }}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=DM+Sans:opsz,wght@9..40,300;9..40,400;9..40,500;9..40,600;9..40,700&family=DM+Serif+Display&display=swap');`}</style>

      <div style={{
        position: "relative", zIndex: 1,
        display: "flex", flexDirection: "column", alignItems: "center",
        gap: 16, padding: 24, background: C.card, borderRadius: 20,
        boxShadow: "0 4px 40px rgba(74,184,140,0.08), 0 1px 3px rgba(0,0,0,0.04)",
        border: `1px solid ${C.border}`, maxWidth: 440,
      }}>

        <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 2 }}>
          <h1 style={{
            fontSize: 26, margin: 0, color: C.text, letterSpacing: 1,
            fontFamily: "'DM Serif Display', Georgia, serif", fontWeight: 400,
          }}>Ritual Puzzle</h1>
          <span style={{ fontSize: 11, color: C.textMuted, fontWeight: 400, letterSpacing: 0.5 }}>
            created by badang
          </span>
        </div>

        <div style={{ display: "flex", gap: 28, fontSize: 13, color: C.textSoft }}>
          <span>Moves <b style={{ color: C.accent, fontSize: 16, fontWeight: 700 }}>{moves}</b></span>
          <span>Time <b style={{ color: C.accent, fontSize: 16, fontWeight: 700 }}>{fmt(sec)}</b></span>
        </div>

        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", justifyContent: "center", alignItems: "center" }}>
          {[3, 4, 5].map((v) => (
            <button key={v} onClick={() => reset(v)} style={btnS(n === v)}>{v}×{v}</button>
          ))}
          <button onClick={() => reset(n)} style={btnS(false)}>Shuffle</button>
          {IMAGES.length > 1 && (
            <button onClick={() => setShowGallery(!showGallery)} style={btnS(showGallery)}>Images</button>
          )}
        </div>

        {showGallery && IMAGES.length > 1 && (
          <div style={{
            background: C.bg, border: `1px solid ${C.border}`,
            borderRadius: 12, padding: 14, width: SIZE, maxHeight: 200, overflowY: "auto",
          }}>
            <div style={{ marginBottom: 10 }}>
              <span style={{ color: C.textSoft, fontSize: 12, fontWeight: 600, letterSpacing: 0.5 }}>
                Choose an Image
              </span>
            </div>
            <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
              {IMAGES.map((img, idx) => (
                <div key={idx} onClick={() => selectImage(idx)} style={{
                  width: 68, height: 68, borderRadius: 10, cursor: "pointer",
                  backgroundImage: `url(${img.src})`, backgroundSize: "cover", backgroundPosition: "center",
                  border: selIdx === idx ? `2.5px solid ${C.accent}` : `2px solid ${C.border}`,
                  transition: "all 0.15s",
                  boxShadow: selIdx === idx ? `0 0 0 3px ${C.accentSoft}` : "none",
                }} />
              ))}
            </div>
          </div>
        )}

        <div style={{
          padding: 4, borderRadius: 14,
          background: `linear-gradient(135deg, ${C.accentMid}, ${C.border})`,
        }}>
          <div style={{
            width: SIZE, height: SIZE, position: "relative",
            borderRadius: 11, overflow: "hidden", background: C.bg,
          }}>
            {board.map((tileIdx, pos) => {
              const isEmpty = tileIdx === n * n - 1 && !won;
              const col = pos % n, row = Math.floor(pos / n);
              const origCol = tileIdx % n, origRow = Math.floor(tileIdx / n);
              return (
                <div key={tileIdx} onClick={() => !isEmpty && tryMove(pos)} style={{
                  position: "absolute", width: T, height: T,
                  left: col * T, top: row * T,
                  transition: "left 0.16s ease-out, top 0.16s ease-out",
                  opacity: isEmpty ? 0 : 1,
                  cursor: isEmpty ? "default" : "pointer",
                  backgroundImage: isEmpty ? "none" : `url(${imgSrc})`,
                  backgroundSize: `${SIZE}px ${SIZE}px`,
                  backgroundPosition: `-${origCol * T}px -${origRow * T}px`,
                  border: isEmpty ? "none" : `1px solid rgba(74,184,140,0.15)`,
                  boxSizing: "border-box", borderRadius: 2,
                }} />
              );
            })}
          </div>
        </div>

        <span onClick={() => setShowHint(!showHint)} style={{
          fontSize: 12, color: showHint ? C.accent : C.textMuted,
          cursor: "pointer", userSelect: "none", fontWeight: 500,
        }}>{showHint ? "Hide Preview" : "Show Preview"}</span>
      </div>

      {showHint && (
        <img src={imgSrc} alt="hint" style={{
          position: "fixed", bottom: 16, right: 16,
          width: 100, height: 100, borderRadius: 12,
          border: `2px solid ${C.accentMid}`,
          objectFit: "cover", opacity: 0.85, zIndex: 50,
          boxShadow: "0 4px 20px rgba(0,0,0,0.08)",
        }} />
      )}

      {won && (
        <div style={{
          position: "fixed", inset: 0, background: "rgba(244,249,247,0.92)",
          display: "flex", alignItems: "center", justifyContent: "center",
          flexDirection: "column", gap: 14, zIndex: 100, backdropFilter: "blur(10px)",
        }}>
          <div style={{ fontSize: 48 }}>✨</div>
          <h2 style={{
            fontSize: 28, color: C.text, margin: 0,
            fontFamily: "'DM Serif Display', Georgia, serif", fontWeight: 400,
          }}>Puzzle Complete!</h2>
          <p style={{ color: C.textSoft, fontSize: 14 }}>
            {moves} moves · {Math.floor(sec / 60)}m {sec % 60}s
          </p>
          <button onClick={() => reset(n)} style={btnS(true)}>Play Again</button>
        </div>
      )}
    </div>
  );
}
